#include <iostream>
using namespace std;
class Solution {
public:
    int flipBits(int n) {
        int result = 0;
        for (int i = 0; i < 32; i++) {
            if (n & (1 << i) != 0) {
                result += 1;
            }
        }
        return result;
    }
};
int main() {
    int n;
    cin >> n;
    cout << Solution().flipBits(n) << endl;
    return 0;
}
